DROP TABLE IF EXISTS `ae`;
CREATE TABLE `ae` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `agenda_uid` bigint(20) NOT NULL,
  `event_uid` bigint(20) NOT NULL,
  `state` tinyint(1) NOT NULL DEFAULT '0',
  `featured` tinyint(1) NOT NULL DEFAULT '0',
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  `legacy_id` varchar(30) DEFAULT NULL,
  `user_uid` bigint(20) DEFAULT NULL,
  `can_edit` tinyint(4) DEFAULT '0',
  `source_agenda_uid` varchar(300) DEFAULT NULL,
  `aggregated` tinyint(1) DEFAULT '0',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2566596 DEFAULT CHARSET=utf8;

